(function (global) {
  const ns = global.AppBackend || {};
  function getClient() {
    if (!ns.getSupabaseClient) throw new Error("Supabase client not available");
    const client = ns.getSupabaseClient();
    if (!client) throw new Error("Supabase client not configured");
    return client;
  }
  function isLoginPage() {
    const body = global.document && global.document.body;
    if (body && body.getAttribute("data-auth-entry") === "login") {
      return true;
    }
    return Boolean(global.location && /\/login\.html$/i.test(global.location.pathname || ""));
  }
  function setStatus(id, message, isError) {
    const el = document.getElementById(id);
    if (!el) return;
    el.textContent = message || "";
    el.className = isError ? "auth-status error" : "auth-status success";
    el.style.display = message ? "block" : "none";
  }
  function clearStatuses() {
    ["login-status", "signup-status", "recovery-status"].forEach(function (id) {
      setStatus(id, "", false);
    });
  }
  function resolvePrimaryRole(roles) {
    const roleSet = new Set((roles || []).map(function (role) {
      return String(role).toLowerCase();
    }));
    if (roleSet.has("admin")) return "admin";
    if (roleSet.has("staff")) return "staff";
    if (roleSet.has("buyer")) return "buyer";
    return null;
  }
  function getRedirectTarget() {
    if (!global.location || !ns.sanitizeRedirectTarget) {
      return null;
    }
    const params = new URLSearchParams(global.location.search || "");
    return ns.sanitizeRedirectTarget(params.get("redirect") || "");
  }
  function buildAuthEntryRedirect(flowType) {
    if (!ns.resolveEmailRedirectUrl) {
      return undefined;
    }
    const baseUrl = ns.resolveEmailRedirectUrl("/login.html");
    if (!baseUrl) {
      return undefined;
    }
    const url = new URL(baseUrl);
    if (flowType) {
      url.searchParams.set("auth_flow", flowType);
    }
    const redirectTarget = getRedirectTarget();
    if (redirectTarget && ns.toRelativeAppHref) {
      const relativeTarget = ns.toRelativeAppHref(redirectTarget);
      if (relativeTarget) {
        url.searchParams.set("redirect", relativeTarget);
      }
    }
    return url.toString();
  }
  function showRecoveryForm(message, isError) {
    if (!isLoginPage()) return;
    const mainRow = document.getElementById("auth-main-row");
    const recoveryRow = document.getElementById("recovery-row");
    if (mainRow) mainRow.style.display = "none";
    if (recoveryRow) recoveryRow.style.display = "";
    const recoveryUserNode = document.getElementById("recovery-username");
    if (recoveryUserNode) {
      const authStateUser = ns.authState && ns.authState.user && ns.authState.user.email
        ? String(ns.authState.user.email).trim()
        : "";
      const loginEmailNode = document.getElementById("login-email");
      const formEmail = loginEmailNode ? String(loginEmailNode.value || "").trim() : "";
      recoveryUserNode.value = authStateUser || formEmail;
    }
    if (message) {
      setStatus("recovery-status", message, Boolean(isError));
    }
  }
  function showStandardForms(message, isError, targetStatusId) {
    if (!isLoginPage()) return;
    const mainRow = document.getElementById("auth-main-row");
    const recoveryRow = document.getElementById("recovery-row");
    if (mainRow) mainRow.style.display = "";
    if (recoveryRow) recoveryRow.style.display = "none";
    if (message && targetStatusId) {
      setStatus(targetStatusId, message, Boolean(isError));
    }
  }
  async function upsertUserRow(userId, payload) {
    try {
      const client = getClient();
      await client.from("users").upsert({ id: userId, ...payload });
    } catch (error) {
      console.warn("User profile upsert skipped", error);
    }
  }
  async function handleLogin(event) {
    event.preventDefault();
    clearStatuses();
    const email = (document.getElementById("login-email") || {}).value?.trim();
    const password = (document.getElementById("login-password") || {}).value;
    if (!email || !password) {
      setStatus("login-status", "Email and password are required.", true);
      return;
    }
    setStatus("login-status", "Signing in...", false);
    try {
      if (ns.authController && ns.authController.queuePendingRedirect) {
        ns.authController.queuePendingRedirect("signin", { requireConfirmed: true });
      }
      await ns.authApi.signIn(email, password);
      const user = await ns.authApi.getUser();
      if (user && user.email_confirmed_at === null) {
        if (ns.authController && ns.authController.clearPendingRedirect) {
          ns.authController.clearPendingRedirect();
        }
        await ns.authApi.signOut();
        setStatus("login-status", "Please verify your email before logging in.", true);
        return;
      }
      setStatus("login-status", "Signed in. Redirecting...", false);
    } catch (error) {
      if (ns.authController && ns.authController.clearPendingRedirect) {
        ns.authController.clearPendingRedirect();
      }
      setStatus("login-status", error.message || "Unable to sign in.", true);
    }
  }
  async function handleSignup(event) {
    event.preventDefault();
    clearStatuses();
    const fullName = (document.getElementById("signup-full-name") || {}).value?.trim();
    const companyName = (document.getElementById("signup-company") || {}).value?.trim();
    const email = (document.getElementById("signup-email") || {}).value?.trim();
    const phone = (document.getElementById("signup-phone") || {}).value?.trim();
    const country = (document.getElementById("signup-country") || {}).value?.trim();
    const password = (document.getElementById("signup-password") || {}).value;
    const confirm = (document.getElementById("signup-confirm-password") || {}).value;
    if (!fullName || !companyName || !email || !phone || !country || !password || !confirm) {
      setStatus("signup-status", "All fields are required.", true);
      return;
    }
    if (password.length < 8) {
      setStatus("signup-status", "Password must be at least 8 characters.", true);
      return;
    }
    if (password !== confirm) {
      setStatus("signup-status", "Passwords do not match.", true);
      return;
    }
    setStatus("signup-status", "Creating account...", false);
    try {
      if (ns.authController && ns.authController.queuePendingRedirect) {
        ns.authController.queuePendingRedirect("signup", { requireConfirmed: true });
      }
      const redirectTo = buildAuthEntryRedirect("signup");
      const client = getClient();
      const { data, error } = await client.auth.signUp({
        email,
        password,
        options: {
          emailRedirectTo: redirectTo,
          data: {
            full_name: fullName,
            company_name: companyName,
            phone_whatsapp: phone,
            country_region: country,
            role: "buyer",
          },
        },
      });
      if (error) throw error;
      if (data && data.user) {
        await upsertUserRow(data.user.id, {
          full_name: fullName,
          email: email,
          phone: phone,
          company_name: companyName,
          country: country,
          role: "buyer",
        });
      }
      const loginEmailNode = document.getElementById("login-email");
      if (loginEmailNode) {
        loginEmailNode.value = email;
      }
      if (data && data.session) {
        setStatus("signup-status", "Account created. Redirecting...", false);
        return;
      }
      if (ns.authController && ns.authController.clearPendingRedirect) {
        ns.authController.clearPendingRedirect();
      }
      setStatus("signup-status", redirectTo
        ? "Account created. Please confirm your email. If it does not arrive, use Resend Confirmation Email."
        : "Account created. Please confirm your email. If it does not arrive, use Resend Confirmation Email. The link will use the Supabase Site URL.", false);
    } catch (error) {
      if (ns.authController && ns.authController.clearPendingRedirect) {
        ns.authController.clearPendingRedirect();
      }
      setStatus("signup-status", error.message || "Failed to create account.", true);
    }
  }
  async function handleResendConfirmation(event) {
    event.preventDefault();
    clearStatuses();
    const loginEmail = (document.getElementById("login-email") || {}).value?.trim();
    const signupEmail = (document.getElementById("signup-email") || {}).value?.trim();
    const email = loginEmail || signupEmail;
    if (!email) {
      setStatus("login-status", "Enter your email first, then resend the confirmation email.", true);
      return;
    }
    try {
      const redirectTo = buildAuthEntryRedirect("signup");
      await ns.authApi.resendSignUpConfirmation(email, redirectTo);
      setStatus("login-status", redirectTo
        ? "Confirmation email sent. Check inbox and spam."
        : "Confirmation email sent. Check inbox and spam. The link will use the Supabase Site URL.", false);
    } catch (error) {
      setStatus("login-status", error.message || "Could not resend confirmation email.", true);
    }
  }
  async function handleForgotPassword(event) {
    event.preventDefault();
    clearStatuses();
    const email = (document.getElementById("login-email") || {}).value?.trim();
    if (!email) {
      setStatus("login-status", "Enter your email first.", true);
      return;
    }
    try {
      const redirectTo = buildAuthEntryRedirect("recovery");
      await ns.authApi.resetPassword(email, redirectTo);
      setStatus("login-status", redirectTo
        ? "Password reset email sent."
        : "Password reset email sent. The link will use the Supabase Site URL.", false);
    } catch (error) {
      setStatus("login-status", error.message || "Could not send reset email.", true);
    }
  }
  async function handleRecoverySubmit(event) {
    event.preventDefault();
    clearStatuses();
    const password = (document.getElementById("recovery-password") || {}).value;
    const confirm = (document.getElementById("recovery-confirm-password") || {}).value;
    if (!password || password.length < 8) {
      setStatus("recovery-status", "Password must be at least 8 characters.", true);
      return;
    }
    if (password !== confirm) {
      setStatus("recovery-status", "Passwords do not match.", true);
      return;
    }
    setStatus("recovery-status", "Updating password...", false);
    try {
      await ns.authApi.updatePassword(password);
      setStatus("recovery-status", "Password updated. Redirecting...", false);
      const roles = ns.authState && Array.isArray(ns.authState.roles) ? ns.authState.roles : [];
      const target = ns.authController && ns.authController.resolvePostAuthUrl
        ? ns.authController.resolvePostAuthUrl(roles)
        : (ns.getRoleHomeUrl ? ns.getRoleHomeUrl(roles) : null);
      if (target) {
        global.setTimeout(function () {
          global.location.href = target;
        }, 300);
      }
    } catch (error) {
      setStatus("recovery-status", error.message || "Failed to update password.", true);
    }
  }
  function getRelativeCurrentPath() {
    if (!global.location) {
      return "";
    }
    return global.location.pathname + global.location.search + global.location.hash;
  }
  async function guardProtectedPage() {
    const guardAttr = document.body && document.body.getAttribute("data-guard");
    if (!guardAttr) return;
    const session = await ns.authApi.getSession().catch(function () {
      return null;
    });
    if (!session) {
      const loginUrl = new URL(ns.getAppRoute ? ns.getAppRoute("login") : "/login.html", global.location.origin);
      loginUrl.searchParams.set("redirect", getRelativeCurrentPath());
      global.location.href = loginUrl.toString();
      return;
    }
    const user = session.user || await ns.authApi.getUser().catch(function () {
      return null;
    });
    const roles = user ? await ns.authApi.getMyRoles(user).catch(function () {
      return [];
    }) : [];
    const primaryRole = resolvePrimaryRole(roles);
    if (guardAttr === "admin" && primaryRole !== "admin") {
      global.location.href = ns.getRoleHomeUrl ? ns.getRoleHomeUrl(roles) : (ns.getAppRoute ? ns.getAppRoute("buyer") : "/buyer-portal/dashboard.html");
      return;
    }
    if (guardAttr === "buyer" && (primaryRole === "admin" || primaryRole === "staff")) {
      global.location.href = ns.getRoleHomeUrl ? ns.getRoleHomeUrl(roles) : (ns.getAppRoute ? ns.getAppRoute("admin") : "/admin/dashboard.html");
      return;
    }
    const emailNodes = document.querySelectorAll("[data-user-email]");
    emailNodes.forEach(function (node) {
      node.textContent = user && user.email ? user.email : "";
    });
    const roleNodes = document.querySelectorAll("[data-user-role]");
    roleNodes.forEach(function (node) {
      node.textContent = primaryRole || roles.join(", ");
    });
  }
  function wireForms() {
    const loginForm = document.getElementById("login-form");
    if (loginForm) {
      loginForm.addEventListener("submit", function (event) {
        void handleLogin(event);
      });
    }
    const forgotBtn = document.getElementById("login-forgot");
    if (forgotBtn) {
      forgotBtn.addEventListener("click", function (event) {
        void handleForgotPassword(event);
      });
    }
    const resendBtn = document.getElementById("login-resend");
    if (resendBtn) {
      resendBtn.addEventListener("click", function (event) {
        void handleResendConfirmation(event);
      });
    }
    const signupForm = document.getElementById("signup-form");
    if (signupForm) {
      signupForm.addEventListener("submit", function (event) {
        void handleSignup(event);
      });
    }
    const recoveryForm = document.getElementById("recovery-form");
    if (recoveryForm) {
      recoveryForm.addEventListener("submit", function (event) {
        void handleRecoverySubmit(event);
      });
    }
    const recoveryBack = document.getElementById("recovery-back");
    if (recoveryBack) {
      recoveryBack.addEventListener("click", function () {
        showStandardForms("", false, "");
      });
    }
  }
  function wireLogoutButtons() {
    document.addEventListener("click", function (event) {
      const trigger = event.target && event.target.closest ? event.target.closest(".js-logout") : null;
      if (!trigger) return;
      event.preventDefault();
      const indexUrl = ns.getAppRoute ? ns.getAppRoute("index") : "/index.html";
      ns.authApi.signOut()
        .catch(function (error) {
          console.warn("Supabase signOut reported an issue", error);
        })
        .finally(function () {
          global.location.href = indexUrl;
        });
    });
  }
  function handleAuthEvent(detail) {
    if (!detail) return;
    if (detail.event === "PASSWORD_RECOVERY" || detail.recoveryMode) {
      showRecoveryForm("Reset link verified. Enter your new password.", false);
      return;
    }
    if (detail.event === "SIGNED_OUT" && isLoginPage()) {
      showStandardForms("", false, "");
      return;
    }
    if (isLoginPage() && detail.user && !detail.recoveryMode) {
      const flowType = detail.flowType || "";
      if (flowType === "signup") {
        setStatus("login-status", "Email confirmed. Redirecting...", false);
      } else if (detail.event === "SIGNED_IN") {
        setStatus("login-status", "Signed in. Redirecting...", false);
      }
    }
  }
  function wireAuthEvents() {
    global.addEventListener("app-auth-event", function (event) {
      handleAuthEvent(event.detail || {});
    });
  }
  function init() {
    if (!ns.hasSupabaseConfig || !ns.hasSupabaseConfig()) {
      console.warn("Supabase config missing; auth flows disabled.");
      return;
    }
    wireForms();
    wireLogoutButtons();
    wireAuthEvents();
    if (isLoginPage()) {
      const flowType = ns.authController && ns.authController.getFlowType
        ? ns.authController.getFlowType()
        : "";
      if (flowType === "recovery") {
        showRecoveryForm("Waiting for Supabase session recovery...", false);
      } else {
        showStandardForms("", false, "");
      }
    }
    void guardProtectedPage();
  }
  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", init, { once: true });
  } else {
    init();
  }
})(window);
